from qiskit import QuantumCircuit
from io import BufferedReader
import random
import math


# this is used to read circuits serialized by serialize_circuits, only used in circuits generated by paramed model that consists MS Gate
def deserialize_circuits(f: BufferedReader):
    circuits = []
    content = f.read().split(b"\0")
    index = 0
    while index < len(content):
        qubit_num = content[index].strip()
        if not qubit_num:
            index += 1
            continue
        qc = QuantumCircuit(int(qubit_num))
        index += 1
        while True:
            op = content[index].strip().decode()
            index += 1
            if op == "":
                break
            params = content[index].strip()
            index += 1
            qubits = content[index].strip()
            index += 1
            # params is [float], for example [1.0]
            params = list(map(float, params[1:-1].split(b", "))) if params else []
            qubits = list(map(int, qubits[1:-1].split(b", "))) if qubits else []
            if op == "rx":
                qc.rx(params[0], qubits[0])
            elif op == "ry":
                qc.ry(params[0], qubits[0])
            elif op == "rxx":
                qc.rxx(params[0], qubits[0], qubits[1])
        circuits.append(qc)
    return circuits


