def random_circuit(n_qubits: int, min_depth: int, max_depth: int):
    qc = QuantumCircuit(n_qubits)
    length = random.randint(min_depth, max_depth)
    for _ in range(length):
        op = random.choice(["rx", "ry", "rxx"])
        if op == "rx":
            qc.rx(math.pi / 4, random.randint(0, n_qubits - 1))
        elif op == "ry":
            qc.ry(math.pi / 4, random.randint(0, n_qubits - 1))
        else:  # rxx
            q1, q2 = random.sample(range(n_qubits), 2)
            qc.rxx(math.pi / 2, q1, q2)

    return qc


def random_circuits(n_circuits: int, n_qubits: int, min_depth: int, max_depth: int):
    return [random_circuit(n_qubits, min_depth, max_depth) for _ in range(n_circuits)]
